/**
 * Filter for macOS-specific filesystem detritus that must never round-trip
 * through a project export. The motivating bug: AppleDouble sidecars
 * (`._foo.ts`, `._\_layout.tsx`) are binary resource-fork blobs but share
 * the source-file extension. When an imported workspace contains them,
 * Metro's Babel parser tries to parse `._\_layout.tsx` as TypeScript and
 * crashes the bundler.
 *
 * Used by every export path (S3 sync tar, /download tar, .shogo-project
 * ZIP, agent-runtime workspace bundle) and by the post-extract scrubber so
 * legacy archives already in S3 also get cleaned on import.
 *
 * Lifted into the SDK from `@shogo/shared-runtime` (was AGPL) under MIT.
 * The original `@shogo/shared-runtime/macos-junk` re-exports this module
 * unchanged for backwards compatibility.
 */
declare function isMacOSJunkName(name: string): boolean;
declare function isMacOSJunkPath(relPath: string): boolean;

export { isMacOSJunkName, isMacOSJunkPath };
